class Solution {
    public int maxPalindromes(String s, int k) {
        int n = s.length();
        int maxCount = 0;
        for (int i = 0; i < n - k + 1; i++) {
            int j = i + k - 1;
            if (isPalindrome(s, i, j)) {
                maxCount++;
            }
        }
        return maxCount;
    }

    private boolean isPalindrome(String s, int i, int j) {
        while (i >= 0 && j < s.length() && s.charAt(i) == s.charAt(j)) {
            i--;
            j++;
        }
        return i >= 0 && j < s.length();
    }
}
```

